/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications via email.
 * Each user has one preferences record. If none exists, defaults apply
 * (all notifications enabled, immediate frequency).
 */

import type { NotificationType } from './notification.js';

/**
 * How often batched email notifications are delivered.
 * - 'immediate': send as events occur
 * - 'daily': batch into a daily digest
 * - 'weekly': batch into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Notification categories that a user can subscribe to or unsubscribe from.
 * Maps directly to NotificationType values.
 */
export type NotificationCategory = NotificationType;

/**
 * Email-specific notification settings.
 */
export interface EmailNotificationSettings {
  enabled: boolean;
  frequency: EmailFrequency;
  unsubscribedCategories: NotificationCategory[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationSettings;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences (userId required, rest has defaults).
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailNotificationSettings>;
}

/**
 * Input for updating existing preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailNotificationSettings>;
}

/**
 * Default email notification settings applied when no preferences exist.
 */
export const DEFAULT_EMAIL_SETTINGS: EmailNotificationSettings = {
  enabled: true,
  frequency: 'immediate',
  unsubscribedCategories: [],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationCategory, EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        unsubscribedCategories: JSON.parse(
          record['emailUnsubscribedCategories'] as string,
        ) as NotificationCategory[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailUnsubscribedCategories: JSON.stringify(entity.email.unsubscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations for user notification preferences and provides
 * a query interface used by NotificationService to check whether a
 * notification should be sent to a given user.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  NotificationCategory,
} from '../models/user-preferences.js';
import { DEFAULT_EMAIL_SETTINGS } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Create preferences for a user. Merges provided settings with defaults.
   * Throws if preferences already exist for the user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId: input.userId,
      email: {
        ...DEFAULT_EMAIL_SETTINGS,
        ...input.email,
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    return prefs;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, falling back to defaults if none exist.
   */
  getPreferencesOrDefaults(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_SETTINGS },
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  /**
   * Update a user's preferences. Only provided fields are changed.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? { ...existing.email, ...input.email }
      : existing.email;

    const updated = this.preferencesRepository.update(existing.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Delete a user's preferences (resets to defaults).
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }

    return this.preferencesRepository.delete(existing.id);
  }

  /**
   * Check whether a specific email notification should be sent to a user.
   * Returns true if email is enabled and the category is not unsubscribed.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferencesOrDefaults(userId);

    if (!prefs.email.enabled) {
      this.logger.debug(`Email disabled for user: ${userId}`);
      return false;
    }

    if (prefs.email.unsubscribedCategories.includes(notificationType as NotificationCategory)) {
      this.logger.debug(
        `User ${userId} unsubscribed from category: ${notificationType}`,
      );
      return false;
    }

    return true;
  }
}

