/**
 * Dispatch a notification through the appropriate adapter.
 * If no adapter is registered for the channel, the notification is stored
 * with 'pending' status (useful for in-app notifications or deferred delivery).
 *
 * When a PreferencesService is configured, checks user preferences before
 * sending. If the user has disabled the channel or unsubscribed from the
 * notification category, the notification is silently skipped.
 */
private dispatchNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
}): void {
  // Check user preferences if a preferences service is configured
  if (this.preferencesService) {
    const userId = params.metadata['userId'] as string | undefined;
    if (userId && params.channel === 'email') {
      if (!this.preferencesService.shouldSendEmail(userId, params.type)) {
        this.logger.info(
          `Notification ${params.type} skipped for user ${userId} due to preferences`,
        );
        return;
      }
    }
  }

