import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.unsubscribedCategories).toEqual([]);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          frequency: 'daily',
          unsubscribedCategories: ['order_status_update'],
        },
      });

      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.unsubscribedCategories).toEqual(['order_status_update']);
    });

    it('should throw when preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const prefs1 = service.createPreferences({ userId: 'user-1' });
      const prefs2 = service.createPreferences({ userId: 'user-2' });

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for a user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });
  });

  describe('getPreferencesOrDefaults', () => {
    it('should return existing preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly' },
      });

      const prefs = service.getPreferencesOrDefaults('user-1');
      expect(prefs.email.frequency).toBe('weekly');
    });

    it('should return defaults when no preferences exist', () => {
      const prefs = service.getPreferencesOrDefaults('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.unsubscribedCategories).toEqual([]);
    });
  });

  describe('updatePreferences', () => {
    it('should update email settings', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should disable email notifications', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
    });

    it('should update unsubscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { unsubscribedCategories: ['order_confirmation', 'user_welcome'] },
      });

      expect(updated.email.unsubscribedCategories).toEqual([
        'order_confirmation',
        'user_welcome',
      ]);
    });

    it('should throw when preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-1');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false when no preferences exist', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true with default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is unsubscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { unsubscribedCategories: ['order_status_update'] },
      });

      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setPreferencesService(service);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      resetNotificationIdCounter();
    });

    it('should send notification when user has no preferences (defaults)', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
    });

    it('should skip notification when user has disabled email', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotifications()).toHaveLength(0);
    });

    it('should skip notification when user unsubscribed from category', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { unsubscribedCategories: ['order_confirmation'] },
      });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should send welcome email when category is not unsubscribed', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { unsubscribedCategories: ['order_confirmation'] },
      });

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(emailAdapter.getSentEmails()[0]?.subject).toContain('Welcome');
    });

    it('should still work without preferences service (backward compatible)', async () => {
      const bus = new EventBus();
      const svc = new NotificationService(bus);
      const adapter = new EmailAdapter();
      svc.registerAdapter(adapter);

      await bus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      expect(adapter.getSentEmails()).toHaveLength(1);
    });
  });
});

